// src/Pages/Services.jsx
import React from 'react';
import ServicesDiamond from '../components/ServicesDiamond';

const cards = [
  {
    id: 'card1',
    src: '/images/chart.svg',
    alt: 'Analytics Icon',
    title: 'Analytics Service',
  },
  {
    id: 'card2',
    src: '/images/chart.svg',
    alt: 'SEO Icon',
    title: 'SEO Service',
  },
  {
    id: 'card3',
    src: '/images/chart.svg',
    alt: 'Development Icon',
    title: 'Development Service',
  },
];

export default function Services() {
  return (
    <div className="page-wrapper">
      {/* Hero Section (same as Homepage) */}
      <div className="hero-inner">
        <h1 className="hero-title">Our Services</h1>
        <p className="hero-subtitle">
          We offer a range of tech solutions to help your business grow.
        </p>
      </div>

      {/* Services Diamonds */}
      <div
        className="row row-collapse align-equal align-center cards-wrapper"
        style={{ position: 'relative' }}
      >
        {cards.map(({ id, src, alt, title }) => (
          <div
            key={id}
            className={`col ${id} medium-6 small-12 large-6`}
            style={{
              position: 'absolute',
              top: '50%',
              left: '50%',
              transform: 'translate(-50%, -50%)',
              willChange: 'transform',
            }}
          >
            <div className="col-inner text-center">
              <ServicesDiamond
                src={src}
                alt={alt}
                title={title}
                className={id}
              />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
